lessons.theory:
## setState
In a `StatefulWidget`, calling `setState` triggers a UI rebuild with the new data.
```dart
void increment() {
  setState(() { count++; });
}
```

lessons.starterCode:
import 'package:flutter/material.dart';

class CounterState extends State<StatefulWidget> {
  int _count = 0;

  void increment() {
    ___(() {
      _count___
    });
  }
  @override Widget build(BuildContext context) => Text('$_count');
}

lessons.solution:
import 'package:flutter/material.dart';
class CounterState extends State<StatefulWidget> {
  int _count = 0;
  void increment() {
    setState(() {
      _count++;
    });
  }
  @override Widget build(BuildContext context) => Text('$_count');
}

